// DUAL-RECORD-WRITE: A1 writes two records with different scopes
// PRIVATE: full profile — only this user reads it
// GLOBAL: curated 4-field subset — any node in the tenant may read it
// B1 and B2 read from GLOBAL only — cannot access challenges[] by architecture

// Record 1: Full business profile (PRIVATE)
await this.db.storeDocument(BUSINESS_PROFILES_INDEX, {
  profileId, userId, tenantId,
  skills: input.skills, goals: input.goals, challenges: input.challenges,
  industryCode, businessStage, locationProximity, teamSizeTier,
  connectionType: 'FLOW_SCOPED', knowledgeScope: 'PRIVATE',  // ← PRIVATE
}, profileId);

// Record 2: Matching profile (GLOBAL — match-safe fields ONLY)
await this.db.storeDocument(MATCHING_PROFILES_INDEX, {
  matchingProfileId, userId, tenantId,
  industryCode,       // ← public
  businessStage,      // ← public
  locationProximity,  // ← computed tier (local/regional/national/international)
  teamSizeTier,       // ← derived tier (micro/small/medium/large)
  // challenges[], goals[], revenue NEVER here — PRIVATE fields
  connectionType: 'FLOW_SCOPED', knowledgeScope: 'GLOBAL',  // ← GLOBAL
}, matchingProfileId);

// Both writes happen BEFORE BusinessProfileCreated emit (DNA-8)
